project.file:
# semon test directory

The executable self-test harness is built as `build/lxd/semon_test` in Debug mode.

Run:

```bash
cd build
make OS=Linux ARCH=AMD64 MODE=Debug
./lxd/semon_test
```

The thin `src/test_entry.cpp` delegates to `core::runSelfTests()`, which exercises:

1. native page allocation and page-chain telemetry;
2. direction-agnostic pin locking;
3. `Virtual3PinGate` AND constraint propagation;
4. deterministic PRNG sequence equality;
5. mathematical parsing and AST allocation;
6. model-to-circuit synthesis.

Additional fuzzing, cryptographic forward-propagation vectors, allocator stress tests, and persistence round-trip tests should be added here as separate harness translation units or data files.

#include "core/Shell.hpp"

int main(int argc, char** argv)
{
    semon::core::Shell shell;
    return shell.run(argc, argv);
}

#include "core/TestSupport.hpp"

int main(int argc, char** argv)
{
    (void)argc;
    (void)argv;
    return semon::core::runSelfTests();
}

#include "persistence/JsonStreaming.hpp"

#include <cstdio>
#include <cstring>

namespace semon {
namespace persistence {

JsonWriter::JsonWriter(bool (*write_fn)(const char* block, std::size_t length, void* userdata), void* userdata)
    : write_fn_(write_fn),
      write_func_(static_cast<std::size_t (*)(const char*, std::size_t, void*)>(0)),
      userdata_(userdata),
      ok_(write_fn != static_cast<bool (*)(const char*, std::size_t, void*)>(0))
{
}

JsonWriter::JsonWriter(std::size_t (*write_func)(const char* data, std::size_t size, void* userdata), void* userdata)
    : write_fn_(static_cast<bool (*)(const char*, std::size_t, void*)>(0)),
      write_func_(write_func),
      userdata_(userdata),
      ok_(write_func != static_cast<std::size_t (*)(const char*, std::size_t, void*)>(0))
{
}

bool JsonWriter::ok() const
{
    return ok_;
}

bool JsonWriter::writeRaw(const char* text)
{
    return text != static_cast<const char*>(0) && writeRaw(text, std::strlen(text));
}

bool JsonWriter::writeRaw(const char* text, std::size_t length)
{
    return emit(text, length);
}

bool JsonWriter::writeString(const char* text)
{
    if (!emit("\"", 1U)) {
        return false;
    }
    if (!escapeAndWrite(text)) {
        return false;
    }
    return emit("\"", 1U);
}

bool JsonWriter::writeNumber(std::uint64_t value)
{
    char buffer[32];
    const int written = std::snprintf(buffer, sizeof(buffer), "%llu", static_cast<unsigned long long>(value));
    if (written <= 0) {
        ok_ = false;
        return false;
    }
    return emit(buffer, static_cast<std::size_t>(written));
}

bool JsonWriter::writeBool(bool value)
{
    return value ? emit("true", 4U) : emit("false", 5U);
}

bool JsonWriter::writeKey(const char* key)
{
    if (!writeString(key)) {
        return false;
    }
    return emit(":", 1U);
}

bool JsonWriter::emit(const char* data, std::size_t size)
{
    if (!ok_ || data == static_cast<const char*>(0)) {
        ok_ = false;
        return false;
    }

    if (write_fn_ != static_cast<bool (*)(const char*, std::size_t, void*)>(0)) {
        ok_ = write_fn_(data, size, userdata_);
    } else {
        const std::size_t written = write_func_(data, size, userdata_);
        ok_ = written == size;
    }
    return ok_;
}

bool JsonWriter::escapeAndWrite(const char* text)
{
    if (text == static_cast<const char*>(0)) {
        return true;
    }

    const char* current = text;
    while (*current != '\0') {
        if (*current == '"' || *current == '\\') {
            if (!emit("\\", 1U) || !emit(current, 1U)) {
                return false;
            }
        } else if (*current == '\n') {
            if (!emit("\\n", 2U)) {
                return false;
            }
        } else if (*current == '\r') {
            if (!emit("\\r", 2U)) {
                return false;
            }
        } else if (*current == '\t') {
            if (!emit("\\t", 2U)) {
                return false;
            }
        } else {
            if (!emit(current, 1U)) {
                return false;
            }
        }
        current += 1;
    }
    return true;
}

JsonReader::JsonReader(std::size_t (*read_fn)(char* buffer, std::size_t max_length, void* userdata), void* userdata)
    : read_fn_(read_fn),
      userdata_(userdata),
      buffer_(),
      position_(0U),
      length_(0U),
      eof_(false),
      ok_(read_fn != static_cast<std::size_t (*)(char*, std::size_t, void*)>(0)),
      error_()
{
}

bool JsonReader::ok() const
{
    return ok_;
}

bool JsonReader::eof() const
{
    return eof_;
}

char JsonReader::peek()
{
    if (!refill()) {
        return '\0';
    }
    return buffer_[position_];
}

char JsonReader::get()
{
    if (!refill()) {
        return '\0';
    }
    const char value = buffer_[position_];
    position_ += 1U;
    return value;
}

bool JsonReader::consume(char expected)
{
    skipWhitespace();
    if (peek() != expected) {
        return false;
    }
    (void)get();
    return true;
}

bool JsonReader::consume(const char* text)
{
    skipWhitespace();
    const std::size_t length = std::strlen(text);
    for (std::size_t index = 0U; index < length; ++index) {
        if (get() != text[index]) {
            return setError("expected token");
        }
    }
    return true;
}

void JsonReader::skipWhitespace()
{
    while (peek() == ' ' || peek() == '\t' || peek() == '\n' || peek() == '\r') {
        (void)get();
    }
}

bool JsonReader::readString(char* destination, std::size_t destination_size)
{
    if (destination == static_cast<char*>(0) || destination_size == 0U) {
        return false;
    }
    skipWhitespace();
    if (!consume('"')) {
        return setError("expected string");
    }

    std::size_t index = 0U;
    while (!eof_) {
        char current = get();
        if (current == '"') {
            destination[index] = '\0';
            return true;
        }
        if (current == '\\') {
            const char escaped = get();
            if (escaped == 'n') {
                current = '\n';
            } else if (escaped == 'r') {
                current = '\r';
            } else if (escaped == 't') {
                current = '\t';
            }
        }
        if ((index + 1U) < destination_size) {
            destination[index] = current;
            index += 1U;
        }
    }
    return setError("unterminated string");
}

bool JsonReader::readUnsigned(std::uint64_t* value)
{
    if (value == static_cast<std::uint64_t*>(0)) {
        return false;
    }
    skipWhitespace();
    std::uint64_t result = 0ULL;
    bool found = false;
    while (peek() >= '0' && peek() <= '9') {
        result = (result * 10ULL) + static_cast<std::uint64_t>(get() - '0');
        found = true;
    }
    if (!found) {
        return setError("expected number");
    }
    *value = result;
    return true;
}

bool JsonReader::readBool(bool* value)
{
    if (value == static_cast<bool*>(0)) {
        return false;
    }
    if (consume("true")) {
        *value = true;
        return true;
    }
    if (consume("false")) {
        *value = false;
        return true;
    }
    return setError("expected bool");
}

bool JsonReader::refill()
{
    if (!ok_) {
        return false;
    }
    if (position_ < length_) {
        return true;
    }
    if (eof_) {
        return false;
    }

    length_ = read_fn_(buffer_, sizeof(buffer_), userdata_);
    position_ = 0U;
    if (length_ == 0U) {
        eof_ = true;
        return false;
    }
    return true;
}

bool JsonReader::setError(const char* message)
{
    ok_ = false;
    if (message != static_cast<const char*>(0)) {
        std::size_t index = 0U;
        while ((index + 1U) < sizeof(error_) && message[index] != '\0') {
            error_[index] = message[index];
            index += 1U;
        }
        error_[index] = '\0';
    } else {
        error_[0] = '\0';
    }
    return false;
}

} // namespace persistence
} // namespace semon

#include "diagnostics/Diagnostics.hpp"

#include "core/SystemSettings.hpp"

namespace semon {
namespace diagnostics {

bool g_errorFlag = false;

namespace {
DiagnosticRecord g_last_record = {
    static_cast<const char*>(0),
    static_cast<void*>(0),
    0U,
    static_cast<std::uint32_t>(DiagnosticCode::NONE),
    0ULL,
    {0}
};
std::uint64_t g_cycle_count = 0ULL;
}

void Diagnostics::clear()
{
    g_errorFlag = false;
    g_last_record.component = static_cast<const char*>(0);
    g_last_record.page_address = static_cast<void*>(0);
    g_last_record.object_offset = 0U;
    g_last_record.code = static_cast<std::uint32_t>(DiagnosticCode::NONE);
    g_last_record.cycle_count = 0ULL;
    g_last_record.label[0] = '\0';
    g_cycle_count = 0ULL;
}

void Diagnostics::set(DiagnosticCode code,
                      const char* component,
                      void* page_address,
                      std::size_t object_offset,
                      const char* label)
{
    g_errorFlag = true;
    g_last_record.component = component;
    g_last_record.page_address = page_address;
    g_last_record.object_offset = object_offset;
    g_last_record.code = static_cast<std::uint32_t>(code);
    g_last_record.cycle_count = g_cycle_count;
    if (label != static_cast<const char*>(0)) {
        std::size_t index = 0U;
        while ((index + 1U) < sizeof(g_last_record.label) && label[index] != '\0') {
            g_last_record.label[index] = label[index];
            index += 1U;
        }
        g_last_record.label[index] = '\0';
    } else {
        g_last_record.label[0] = '\0';
    }
}

DiagnosticRecord Diagnostics::lastRecord()
{
    return g_last_record;
}

std::uint64_t Diagnostics::cycleCount()
{
    return g_cycle_count;
}

void Diagnostics::enterLoop()
{
    g_cycle_count += 1ULL;
    if (g_cycle_count > core::SystemSettings::MAX_LOOP_CYCLES) {
        Diagnostics::set(DiagnosticCode::LIMIT,
                         "loop-watchdog",
                         static_cast<void*>(0),
                         0U,
                         "MAX_LOOP_CYCLES");
    }
}

void Diagnostics::enterLoop(std::uint64_t current_cycle)
{
    if (current_cycle > g_cycle_count) {
        g_cycle_count = current_cycle;
    } else {
        g_cycle_count += 1ULL;
    }

    if (g_cycle_count > core::SystemSettings::MAX_LOOP_CYCLES) {
        Diagnostics::set(DiagnosticCode::LIMIT,
                         "loop-watchdog",
                         static_cast<void*>(0),
                         0U,
                         "MAX_LOOP_CYCLES");
    }
}

} // namespace diagnostics
} // namespace semon

#include "math/ExpressionParser.hpp"

#include <cstring>

namespace semon {
namespace math {

ExpressionParser::ExpressionParser(MathModel& model)
    : model_(&model),
      text_(static_cast<const char*>(0)),
      position_(0U)
{
}

bool ExpressionParser::parse(const char* text, ExpressionNode** root, char* error, std::size_t error_size)
{
    if (root == static_cast<ExpressionNode**>(0)) {
        return setError(error, error_size, "null root");
    }

    text_ = text;
    position_ = 0U;
    *root = static_cast<ExpressionNode*>(0);

    if (!parseExpression(root, error, error_size)) {
        return false;
    }

    skipWhitespace();
    if (text_ == static_cast<const char*>(0) || text_[position_] != '\0') {
        return setError(error, error_size, "trailing input");
    }

    return *root != static_cast<ExpressionNode*>(0);
}

bool ExpressionParser::parseExpression(ExpressionNode** node, char* error, std::size_t error_size)
{
    return parseConcat(node, error, error_size);
}

bool ExpressionParser::parseConcat(ExpressionNode** node, char* error, std::size_t error_size)
{
    if (!parseOr(node, error, error_size)) {
        return false;
    }

    while (consume("||")) {
        ExpressionNode* right = static_cast<ExpressionNode*>(0);
        if (!parseOr(&right, error, error_size)) {
            return false;
        }
        *node = model_->makeOperationNode(MathOperation::CONCAT, *node, right);
        if (*node == static_cast<ExpressionNode*>(0)) {
            return setError(error, error_size, "allocation failed");
        }
    }
    return true;
}

bool ExpressionParser::parseOr(ExpressionNode** node, char* error, std::size_t error_size)
{
    if (!parseXor(node, error, error_size)) {
        return false;
    }

    while (true) {
        skipWhitespace();
        if (text_[position_] == '|' && text_[position_ + 1U] == '|') {
            break;
        }
        if (!consume('|')) {
            break;
        }
        ExpressionNode* right = static_cast<ExpressionNode*>(0);
        if (!parseXor(&right, error, error_size)) {
            return false;
        }
        *node = model_->makeOperationNode(MathOperation::OR, *node, right);
        if (*node == static_cast<ExpressionNode*>(0)) {
            return setError(error, error_size, "allocation failed");
        }
    }
    return true;
}

bool ExpressionParser::parseXor(ExpressionNode** node, char* error, std::size_t error_size)
{
    if (!parseAnd(node, error, error_size)) {
        return false;
    }

    while (consume('^')) {
        ExpressionNode* right = static_cast<ExpressionNode*>(0);
        if (!parseAnd(&right, error, error_size)) {
            return false;
        }
        *node = model_->makeOperationNode(MathOperation::XOR, *node, right);
        if (*node == static_cast<ExpressionNode*>(0)) {
            return setError(error, error_size, "allocation failed");
        }
    }
    return true;
}

bool ExpressionParser::parseAnd(ExpressionNode** node, char* error, std::size_t error_size)
{
    if (!parseEquality(node, error, error_size)) {
        return false;
    }

    while (true) {
        skipWhitespace();
        if (text_[position_] == '&' && text_[position_ + 1U] == '&') {
            position_ += 2U;
        } else if (!consume('&')) {
            break;
        }
        ExpressionNode* right = static_cast<ExpressionNode*>(0);
        if (!parseEquality(&right, error, error_size)) {
            return false;
        }
        *node = model_->makeOperationNode(MathOperation::AND, *node, right);
        if (*node == static_cast<ExpressionNode*>(0)) {
            return setError(error, error_size, "allocation failed");
        }
    }
    return true;
}

bool ExpressionParser::parseEquality(ExpressionNode** node, char* error, std::size_t error_size)
{
    if (!parseShift(node, error, error_size)) {
        return false;
    }

    MathOperation relation = MathOperation::NONE;
    if (consume("==")) {
        relation = MathOperation::EQ;
    } else if (consume("!=")) {
        relation = MathOperation::NE;
    } else if (consume("<=")) {
        relation = MathOperation::LE;
    } else if (consume(">=")) {
        relation = MathOperation::GE;
    } else if (consume('<')) {
        relation = MathOperation::LT;
    } else if (consume('>')) {
        relation = MathOperation::GT;
    }

    if (relation != MathOperation::NONE) {
        ExpressionNode* right = static_cast<ExpressionNode*>(0);
        if (!parseShift(&right, error, error_size)) {
            return false;
        }
        *node = model_->makeOperationNode(relation, *node, right);
        if (*node == static_cast<ExpressionNode*>(0)) {
            return setError(error, error_size, "allocation failed");
        }
    }
    return true;
}

bool ExpressionParser::parseShift(ExpressionNode** node, char* error, std::size_t error_size)
{
    if (!parseTerm(node, error, error_size)) {
        return false;
    }

    while (true) {
        if (consume("<<")) {
            ExpressionNode* right = static_cast<ExpressionNode*>(0);
            if (!parseTerm(&right, error, error_size)) {
                return false;
            }
            *node = model_->makeOperationNode(MathOperation::SHL, *node, right);
        } else if (consume(">>")) {
            ExpressionNode* right = static_cast<ExpressionNode*>(0);
            if (!parseTerm(&right, error, error_size)) {
                return false;
            }
            *node = model_->makeOperationNode(MathOperation::SHR, *node, right);
        } else {
            break;
        }

        if (*node == static_cast<ExpressionNode*>(0)) {
            return setError(error, error_size, "allocation failed");
        }
    }
    return true;
}

bool ExpressionParser::parseTerm(ExpressionNode** node, char* error, std::size_t error_size)
{
    if (!parseFactor(node, error, error_size)) {
        return false;
    }

    while (true) {
        MathOperation operation = MathOperation::NONE;
        if (consume('+')) {
            operation = MathOperation::ADD;
        } else if (consume('-')) {
            operation = MathOperation::SUB;
        } else {
            break;
        }

        ExpressionNode* right = static_cast<ExpressionNode*>(0);
        if (!parseFactor(&right, error, error_size)) {
            return false;
        }
        *node = model_->makeOperationNode(operation, *node, right);
        if (*node == static_cast<ExpressionNode*>(0)) {
            return setError(error, error_size, "allocation failed");
        }
    }
    return true;
}

bool ExpressionParser::parseFactor(ExpressionNode** node, char* error, std::size_t error_size)
{
    if (!parseUnary(node, error, error_size)) {
        return false;
    }

    while (true) {
        MathOperation operation = MathOperation::NONE;
        if (consume('*')) {
            operation = MathOperation::MUL;
        } else if (consume('/')) {
            operation = MathOperation::DIV;
        } else if (consume('%')) {
            operation = MathOperation::MOD;
        } else {
            break;
        }

        ExpressionNode* right = static_cast<ExpressionNode*>(0);
        if (!parseUnary(&right, error, error_size)) {
            return false;
        }
        *node = model_->makeOperationNode(operation, *node, right);
        if (*node == static_cast<ExpressionNode*>(0)) {
            return setError(error, error_size, "allocation failed");
        }
    }
    return true;
}

bool ExpressionParser::parseUnary(ExpressionNode** node, char* error, std::size_t error_size)
{
    skipWhitespace();
    if (consume('!') || consume('~')) {
        if (!parseUnary(node, error, error_size)) {
            return false;
        }
        *node = model_->makeOperationNode(MathOperation::NOT, *node, static_cast<ExpressionNode*>(0));
        return *node != static_cast<ExpressionNode*>(0);
    }

    if (consume('-')) {
        if (!parseUnary(node, error, error_size)) {
            return false;
        }
        ExpressionNode* zero = model_->makeConstantNode(0ULL, 1U);
        *node = model_->makeOperationNode(MathOperation::SUB, zero, *node);
        return *node != static_cast<ExpressionNode*>(0);
    }

    if (consume('+')) {
        return parseUnary(node, error, error_size);
    }

    return parsePrimary(node, error, error_size);
}

bool ExpressionParser::parsePrimary(ExpressionNode** node, char* error, std::size_t error_size)
{
    skipWhitespace();
    *node = static_cast<ExpressionNode*>(0);

    if (consume('(')) {
        if (!parseExpression(node, error, error_size)) {
            return false;
        }
        return consume(')');
    }

    std::uint64_t number = 0ULL;
    if (readNumber(&number)) {
        *node = model_->makeConstantNode(number, 64U);
        return *node != static_cast<ExpressionNode*>(0);
    }

    char identifier[64];
    if (readIdentifier(identifier, sizeof(identifier))) {
        const MathVariable* variable = model_->variableByName(identifier);
        std::uint32_t variable_uid = 0U;
        if (variable == static_cast<const MathVariable*>(0)) {
            if (!model_->addVariable(identifier, 1U, &variable_uid)) {
                return setError(error, error_size, "variable capacity exceeded");
            }
        } else {
            variable_uid = variable->uid;
        }

        ExpressionNode* base = model_->makeVariableNode(variable_uid);
        if (base == static_cast<ExpressionNode*>(0)) {
            return setError(error, error_size, "allocation failed");
        }

        skipWhitespace();
        if (consume('(')) {
            std::int32_t depth = 1;
            while (text_[position_] != '\0' && depth > 0) {
                if (text_[position_] == '(') {
                    depth += 1;
                } else if (text_[position_] == ')') {
                    depth -= 1;
                }
                if (depth > 0) {
                    position_ += 1U;
                }
            }
            if (!consume(')')) {
                return setError(error, error_size, "unterminated call");
            }
            *node = base;
            (*node)->operation = MathOperation::FUNCTION_CALL;
            std::size_t name_index = 0U;
            while ((name_index + 1U) < sizeof((*node)->name) && identifier[name_index] != '\0') {
                (*node)->name[name_index] = identifier[name_index];
                name_index += 1U;
            }
            (*node)->name[name_index] = '\0';
            return true;
        }

        if (consume('[')) {
            std::uint64_t start = 0ULL;
            std::uint64_t end = 0ULL;
            if (!readNumber(&start) || !consume(':') || !readNumber(&end)) {
                return setError(error, error_size, "bad slice");
            }
            if (!consume(']')) {
                return setError(error, error_size, "unterminated slice");
            }
            ExpressionNode* end_node = model_->makeConstantNode(end, 32U);
            *node = model_->makeOperationNode(MathOperation::SLICE, base, end_node);
            if (*node == static_cast<ExpressionNode*>(0)) {
                return setError(error, error_size, "allocation failed");
            }
            (*node)->bit_start = static_cast<std::uint32_t>(start);
            (*node)->bit_end = static_cast<std::uint32_t>(end);
            return true;
        }

        *node = base;
        return true;
    }

    return setError(error, error_size, "expected expression");
}

void ExpressionParser::skipWhitespace()
{
    while (text_[position_] == ' ' || text_[position_] == '\t' || text_[position_] == '\n' || text_[position_] == '\r') {
        position_ += 1U;
    }
}

bool ExpressionParser::consume(char expected)
{
    skipWhitespace();
    if (text_[position_] != expected) {
        return false;
    }
    position_ += 1U;
    return true;
}

bool ExpressionParser::consume(const char* token)
{
    skipWhitespace();
    const std::size_t length = std::strlen(token);
    if (std::strncmp(text_ + position_, token, length) != 0) {
        return false;
    }
    position_ += length;
    return true;
}

bool ExpressionParser::isIdentifierStart(char value) const
{
    return (value >= 'A' && value <= 'Z') ||
           (value >= 'a' && value <= 'z') ||
           value == '_';
}

bool ExpressionParser::isIdentifierContinue(char value) const
{
    return isIdentifierStart(value) || (value >= '0' && value <= '9');
}

bool ExpressionParser::readIdentifier(char* destination, std::size_t destination_size)
{
    skipWhitespace();
    if (destination_size == 0U || !isIdentifierStart(text_[position_])) {
        return false;
    }

    std::size_t index = 0U;
    while (isIdentifierContinue(text_[position_]) && (index + 1U) < destination_size) {
        destination[index] = text_[position_];
        position_ += 1U;
        index += 1U;
    }
    destination[index] = '\0';
    return true;
}

bool ExpressionParser::readNumber(std::uint64_t* value)
{
    skipWhitespace();
    if (value == static_cast<std::uint64_t*>(0)) {
        return false;
    }

    std::uint64_t result = 0ULL;
    std::uint32_t base = 10U;
    if (text_[position_] == '0' && (text_[position_ + 1U] == 'x' || text_[position_ + 1U] == 'X')) {
        base = 16U;
        position_ += 2U;
    }

    bool found = false;
    while (true) {
        const char current = text_[position_];
        std::uint32_t digit = 0U;
        if (current >= '0' && current <= '9') {
            digit = static_cast<std::uint32_t>(current - '0');
        } else if (base == 16U && current >= 'a' && current <= 'f') {
            digit = static_cast<std::uint32_t>(10U + current - 'a');
        } else if (base == 16U && current >= 'A' && current <= 'F') {
            digit = static_cast<std::uint32_t>(10U + current - 'A');
        } else {
            break;
        }

        if (digit >= base) {
            break;
        }
        result = (result * base) + digit;
        position_ += 1U;
        found = true;
    }

    if (!found) {
        return false;
    }

    *value = result;
    return true;
}

bool ExpressionParser::setError(char* error, std::size_t error_size, const char* message) const
{
    if (error != static_cast<char*>(0) && error_size > 0U) {
        std::size_t index = 0U;
        while ((index + 1U) < error_size && message != static_cast<const char*>(0) && message[index] != '\0') {
            error[index] = message[index];
            index += 1U;
        }
        error[index] = '\0';
    }
    return false;
}

} // namespace math
} // namespace semon

#include "math/Synthesizer.hpp"

#include <cstdio>

namespace semon {
namespace math {

bool Synthesizer::compileModelToCircuit(const MathModel& model, circuit::Circuit& target)
{
    for (std::uint32_t variable_index = 0U; variable_index < model.variableCount(); ++variable_index) {
        const MathVariable variable_storage = model.variableByUid(variable_index + 1U) == static_cast<const MathVariable*>(0)
                                                  ? MathVariable()
                                                  : *model.variableByUid(variable_index + 1U);
        const MathVariable* variable = model.variableByUid(variable_storage.uid);
        if (variable == static_cast<const MathVariable*>(0)) {
            continue;
        }

        for (std::uint32_t bit = 0U; bit < variable->bit_width; ++bit) {
            char pin_name[96];
            (void)std::snprintf(pin_name, sizeof(pin_name), "%s:%u", variable->name, bit);
            circuit::Pin* pin = target.addPin(pin_name, variable->uid, bit);
            if (pin == static_cast<circuit::Pin*>(0)) {
                return false;
            }
        }
    }

    for (std::uint32_t equation_index = 0U; equation_index < model.equationCount(); ++equation_index) {
        const MathEquation* equation = model.equationByUid(equation_index + 1U);
        if (equation == static_cast<const MathEquation*>(0)) {
            continue;
        }

        circuit::Pin* lhs_pin = static_cast<circuit::Pin*>(0);
        circuit::Pin* rhs_pin = static_cast<circuit::Pin*>(0);
        if (!emitExpression(model, equation->lhs, target, &lhs_pin) ||
            !emitExpression(model, equation->rhs, target, &rhs_pin)) {
            return false;
        }

        circuit::Virtual3PinGate* gate = static_cast<circuit::Virtual3PinGate*>(0);
        if (!target.addGate(lhs_pin, rhs_pin, static_cast<circuit::Pin*>(0), circuit::Virtual3PinGate::TRUTH_EQUAL, &gate)) {
            return false;
        }
        if (gate != static_cast<circuit::Virtual3PinGate*>(0)) {
            (void)gate;
        }
    }

    return true;
}

bool Synthesizer::emitExpression(const MathModel& model,
                                 const ExpressionNode* node,
                                 circuit::Circuit& target,
                                 circuit::Pin** output_pin)
{
    if (output_pin == static_cast<circuit::Pin**>(0) || node == static_cast<const ExpressionNode*>(0)) {
        return false;
    }
    *output_pin = static_cast<circuit::Pin*>(0);

    if (node->node_type == MathNodeType::VARIABLE) {
        const MathVariable* variable = model.variableByUid(node->variable_uid);
        if (variable == static_cast<const MathVariable*>(0)) {
            return false;
        }
        const std::uint32_t bit_index = node->bit_start;
        if (bit_index >= variable->bit_width) {
            return false;
        }
        char pin_name[96];
        (void)std::snprintf(pin_name, sizeof(pin_name), "%s:%u", variable->name, bit_index);
        *output_pin = target.addPin(pin_name, variable->uid, bit_index);
        return *output_pin != static_cast<circuit::Pin*>(0);
    }

    if (node->node_type == MathNodeType::CONSTANT) {
        char pin_name[64];
        (void)std::snprintf(pin_name, sizeof(pin_name), "const_%llu", static_cast<unsigned long long>(node->value));
        circuit::Pin* pin = target.addPin(pin_name, 0U, 0U);
        if (pin == static_cast<circuit::Pin*>(0)) {
            return false;
        }
        const bool value = ((node->value & 1ULL) != 0ULL);
        (void)target.lockPin(pin, value);
        *output_pin = pin;
        return true;
    }

    if (node->node_type == MathNodeType::OPERATION) {
        if (node->operation == MathOperation::NOT) {
            circuit::Pin* input_pin = static_cast<circuit::Pin*>(0);
            if (!emitExpression(model, node->left, target, &input_pin)) {
                return false;
            }
            char pin_name[64];
            (void)std::snprintf(pin_name, sizeof(pin_name), "not_%u", static_cast<unsigned int>(target.gateCount()));
            circuit::Pin* result = target.addPin(pin_name, 0U, 0U);
            if (result == static_cast<circuit::Pin*>(0)) {
                return false;
            }
            return target.addGate(input_pin, static_cast<circuit::Pin*>(0), result, circuit::Virtual3PinGate::TRUTH_INVERT);
        }

        if (node->operation == MathOperation::SLICE) {
            return emitExpression(model, node->left, target, output_pin);
        }

        if (node->operation == MathOperation::CONCAT) {
            return emitExpression(model, node->left, target, output_pin);
        }

        if (node->operation == MathOperation::FUNCTION_CALL) {
            circuit::Pin* pin = target.addPin(node->name, 0U, 0U);
            if (pin == static_cast<circuit::Pin*>(0)) {
                return false;
            }
            (void)target.lockPin(pin, false);
            *output_pin = pin;
            return true;
        }

        circuit::Pin* left_pin = static_cast<circuit::Pin*>(0);
        circuit::Pin* right_pin = static_cast<circuit::Pin*>(0);
        if (!emitExpression(model, node->left, target, &left_pin) ||
            !emitExpression(model, node->right, target, &right_pin)) {
            return false;
        }
        return emitBinaryGate(model, node, target, left_pin, right_pin, output_pin);
    }

    return false;
}

bool Synthesizer::emitBinaryGate(const MathModel& model,
                                 const ExpressionNode* node,
                                 circuit::Circuit& target,
                                 circuit::Pin* left_pin,
                                 circuit::Pin* right_pin,
                                 circuit::Pin** output_pin)
{
    (void)model;
    if (output_pin == static_cast<circuit::Pin**>(0) || left_pin == static_cast<circuit::Pin*>(0) ||
        right_pin == static_cast<circuit::Pin*>(0)) {
        return false;
    }

    char pin_name[64];
    (void)std::snprintf(pin_name, sizeof(pin_name), "op_%u", static_cast<unsigned int>(target.gateCount()));
    circuit::Pin* result = target.addPin(pin_name, 0U, 0U);
    if (result == static_cast<circuit::Pin*>(0)) {
        return false;
    }

    const std::uint8_t truth = circuit::Virtual3PinGate::truthByteFor(node->operation);
    return target.addGate(left_pin, right_pin, result, truth, static_cast<circuit::Virtual3PinGate**>(0));
}

} // namespace math
} // namespace semon

#include "math/ExpressionParser.hpp"
#include "math/MathModel.hpp"

#include <cstring>

namespace semon {
namespace math {

MathModel::MathModel(core::PagedAllocator* allocator)
    : allocator_(allocator),
      uid_(0U),
      name_(),
      variables_(),
      constants_(),
      equations_(),
      inequalities_(),
      functions_(),
      variable_count_(0U),
      constant_count_(0U),
      equation_count_(0U),
      inequality_count_(0U),
      function_count_(0U),
      next_variable_uid_(1U),
      next_constant_uid_(1U),
      next_equation_uid_(1U),
      next_inequality_uid_(1U),
      next_function_uid_(1U)
{
}

bool MathModel::initialize(std::uint32_t uid, const char* name)
{
    if (!copyName(name_, sizeof(name_), name)) {
        return false;
    }
    uid_ = uid;
    variable_count_ = 0U;
    constant_count_ = 0U;
    equation_count_ = 0U;
    inequality_count_ = 0U;
    function_count_ = 0U;
    next_variable_uid_ = 1U;
    next_constant_uid_ = 1U;
    next_equation_uid_ = 1U;
    next_inequality_uid_ = 1U;
    next_function_uid_ = 1U;
    return true;
}

std::uint32_t MathModel::uid() const
{
    return uid_;
}

const char* MathModel::name() const
{
    return name_;
}

core::PagedAllocator* MathModel::allocator() const
{
    return allocator_;
}

bool MathModel::addVariable(const char* name, std::uint32_t bit_width, std::uint32_t* uid_out)
{
    if (!ensureVariableCapacity() || bit_width == 0U || bit_width > core::SystemSettings::MAXIMUM_BIT_WIDTH) {
        return false;
    }

    MathVariable* variable = &variables_[variable_count_];
    variable->uid = next_variable_uid_;
    (void)copyName(variable->name, sizeof(variable->name), name);
    variable->bit_width = bit_width;
    variable->released = false;
    if (uid_out != static_cast<std::uint32_t*>(0)) {
        *uid_out = variable->uid;
    }
    variable_count_ += 1U;
    next_variable_uid_ += 1U;
    return true;
}

bool MathModel::addConstant(const char* name, std::uint64_t value, std::uint32_t bit_width, std::uint32_t* uid_out)
{
    if (!ensureConstantCapacity() || bit_width == 0U || bit_width > core::SystemSettings::MAXIMUM_BIT_WIDTH) {
        return false;
    }

    MathConstant* constant = &constants_[constant_count_];
    constant->uid = next_constant_uid_;
    (void)copyName(constant->name, sizeof(constant->name), name);
    constant->bit_width = bit_width;
    constant->small_value = static_cast<std::uintptr_t>(value);
    constant->data = static_cast<void*>(0);
    constant->is_medium = false;
    constant->is_large = false;
    if (uid_out != static_cast<std::uint32_t*>(0)) {
        *uid_out = constant->uid;
    }
    constant_count_ += 1U;
    next_constant_uid_ += 1U;
    return true;
}

bool MathModel::addEquation(const char* name, ExpressionNode* lhs, ExpressionNode* rhs, std::uint32_t* uid_out)
{
    if (!ensureEquationCapacity() || lhs == static_cast<ExpressionNode*>(0) || rhs == static_cast<ExpressionNode*>(0)) {
        return false;
    }

    MathEquation* equation = &equations_[equation_count_];
    equation->uid = next_equation_uid_;
    (void)copyName(equation->name, sizeof(equation->name), name);
    equation->lhs = lhs;
    equation->rhs = rhs;
    equation->released = false;
    if (uid_out != static_cast<std::uint32_t*>(0)) {
        *uid_out = equation->uid;
    }
    equation_count_ += 1U;
    next_equation_uid_ += 1U;
    return true;
}

bool MathModel::addInequality(const char* name,
                              ExpressionNode* lhs,
                              ExpressionNode* rhs,
                              MathOperation relation,
                              std::uint32_t* uid_out)
{
    if (!ensureInequalityCapacity() || lhs == static_cast<ExpressionNode*>(0) || rhs == static_cast<ExpressionNode*>(0)) {
        return false;
    }

    MathInequality* inequality = &inequalities_[inequality_count_];
    inequality->uid = next_inequality_uid_;
    (void)copyName(inequality->name, sizeof(inequality->name), name);
    inequality->lhs = lhs;
    inequality->rhs = rhs;
    inequality->relation = relation;
    inequality->released = false;
    if (uid_out != static_cast<std::uint32_t*>(0)) {
        *uid_out = inequality->uid;
    }
    inequality_count_ += 1U;
    next_inequality_uid_ += 1U;
    return true;
}

bool MathModel::addFunction(const char* name,
                            const char* const* arguments,
                            std::uint32_t argument_count,
                            ExpressionNode* body,
                            std::uint32_t* uid_out)
{
    if (!ensureFunctionCapacity() || body == static_cast<ExpressionNode*>(0) || argument_count > 8U) {
        return false;
    }

    MathFunction* function = &functions_[function_count_];
    function->uid = next_function_uid_;
    (void)copyName(function->name, sizeof(function->name), name);
    function->argument_count = argument_count;
    function->body = body;
    function->released = false;
    for (std::uint32_t index = 0U; index < argument_count; ++index) {
        (void)copyName(function->argument_names[index], sizeof(function->argument_names[index]), arguments[index]);
    }
    if (uid_out != static_cast<std::uint32_t*>(0)) {
        *uid_out = function->uid;
    }
    function_count_ += 1U;
    next_function_uid_ += 1U;
    return true;
}

bool MathModel::parseAndAddEquation(const char* text, std::uint32_t* uid_out, char* error, std::size_t error_size)
{
    ExpressionParser parser(*this);
    ExpressionNode* root = static_cast<ExpressionNode*>(0);
    if (!parser.parse(text, &root, error, error_size) || root == static_cast<ExpressionNode*>(0)) {
        return false;
    }

    ExpressionNode* lhs = root;
    ExpressionNode* rhs = root;
    if (root->node_type == MathNodeType::OPERATION) {
        if (root->operation == MathOperation::EQ ||
            root->operation == MathOperation::NE ||
            root->operation == MathOperation::LT ||
            root->operation == MathOperation::GT ||
            root->operation == MathOperation::LE ||
            root->operation == MathOperation::GE) {
            lhs = root->left;
            rhs = root->right;
        } else {
            rhs = makeConstantNode(1ULL, 1U);
        }
    } else {
        rhs = makeConstantNode(1ULL, 1U);
    }

    return addEquation(root->node_type == MathNodeType::OPERATION &&
                           (root->operation == MathOperation::EQ ||
                            root->operation == MathOperation::NE ||
                            root->operation == MathOperation::LT ||
                            root->operation == MathOperation::GT ||
                            root->operation == MathOperation::LE ||
                            root->operation == MathOperation::GE)
                           ? root->name
                           : text,
                       lhs,
                       rhs,
                       uid_out);
}

ExpressionNode* MathModel::makeNode(MathNodeType node_type, MathOperation operation)
{
    if (allocator_ == static_cast<core::PagedAllocator*>(0)) {
        return static_cast<ExpressionNode*>(0);
    }

    ExpressionNode* node = allocator_->allocate<ExpressionNode>(this, core::ObjectType::EXPRESSION_NODE);
    if (node == static_cast<ExpressionNode*>(0)) {
        return static_cast<ExpressionNode*>(0);
    }

    node->left = static_cast<ExpressionNode*>(0);
    node->right = static_cast<ExpressionNode*>(0);
    node->parent_container = this;
    node->variable_uid = 0U;
    node->node_type = node_type;
    node->flags = 0U;
    node->operation = operation;
    node->value = 0ULL;
    node->bit_start = 0U;
    node->bit_end = 0U;
    node->name[0] = '\0';
    return node;
}

ExpressionNode* MathModel::makeVariableNode(std::uint32_t variable_uid)
{
    ExpressionNode* node = makeNode(MathNodeType::VARIABLE, MathOperation::NONE);
    if (node == static_cast<ExpressionNode*>(0)) {
        return static_cast<ExpressionNode*>(0);
    }

    node->variable_uid = variable_uid;
    const MathVariable* variable = variableByUid(variable_uid);
    if (variable != static_cast<const MathVariable*>(0)) {
        (void)copyName(node->name, sizeof(node->name), variable->name);
    }
    return node;
}

ExpressionNode* MathModel::makeConstantNode(std::uint64_t value, std::uint32_t bit_width)
{
    ExpressionNode* node = makeNode(MathNodeType::CONSTANT, MathOperation::NONE);
    if (node == static_cast<ExpressionNode*>(0)) {
        return static_cast<ExpressionNode*>(0);
    }

    node->value = value;
    node->bit_end = bit_width;
    return node;
}

ExpressionNode* MathModel::makeOperationNode(MathOperation operation, ExpressionNode* left, ExpressionNode* right)
{
    ExpressionNode* node = makeNode(MathNodeType::OPERATION, operation);
    if (node == static_cast<ExpressionNode*>(0)) {
        return static_cast<ExpressionNode*>(0);
    }

    node->left = left;
    node->right = right;
    return node;
}

const MathVariable* MathModel::variableByUid(std::uint32_t uid) const
{
    for (std::uint32_t index = 0U; index < variable_count_; ++index) {
        if (variables_[index].uid == uid) {
            return &variables_[index];
        }
    }
    return static_cast<const MathVariable*>(0);
}

const MathVariable* MathModel::variableByName(const char* name) const
{
    for (std::uint32_t index = 0U; index < variable_count_; ++index) {
        if (std::strcmp(variables_[index].name, name) == 0) {
            return &variables_[index];
        }
    }
    return static_cast<const MathVariable*>(0);
}

const MathConstant* MathModel::constantByUid(std::uint32_t uid) const
{
    for (std::uint32_t index = 0U; index < constant_count_; ++index) {
        if (constants_[index].uid == uid) {
            return &constants_[index];
        }
    }
    return static_cast<const MathConstant*>(0);
}

const MathEquation* MathModel::equationByUid(std::uint32_t uid) const
{
    for (std::uint32_t index = 0U; index < equation_count_; ++index) {
        if (equations_[index].uid == uid) {
            return &equations_[index];
        }
    }
    return static_cast<const MathEquation*>(0);
}

const MathFunction* MathModel::functionByName(const char* name) const
{
    for (std::uint32_t index = 0U; index < function_count_; ++index) {
        if (std::strcmp(functions_[index].name, name) == 0) {
            return &functions_[index];
        }
    }
    return static_cast<const MathFunction*>(0);
}

std::uint32_t MathModel::variableCount() const
{
    return variable_count_;
}

std::uint32_t MathModel::constantCount() const
{
    return constant_count_;
}

std::uint32_t MathModel::equationCount() const
{
    return equation_count_;
}

std::uint32_t MathModel::inequalityCount() const
{
    return inequality_count_;
}

std::uint32_t MathModel::functionCount() const
{
    return function_count_;
}

bool MathModel::copyName(char* destination, std::size_t destination_size, const char* source) const
{
    if (destination == static_cast<char*>(0) || destination_size == 0U) {
        return false;
    }

    std::size_t index = 0U;
    while ((index + 1U) < destination_size && source != static_cast<const char*>(0) && source[index] != '\0') {
        destination[index] = source[index];
        index += 1U;
    }
    destination[index] = '\0';
    return true;
}

bool MathModel::ensureVariableCapacity() const
{
    return variable_count_ < core::SystemSettings::MAX_VARIABLES_PER_MODEL;
}

bool MathModel::ensureConstantCapacity() const
{
    return constant_count_ < core::SystemSettings::MAX_CONSTANTS_PER_MODEL;
}

bool MathModel::ensureEquationCapacity() const
{
    return equation_count_ < core::SystemSettings::MAX_EQUATIONS_PER_MODEL;
}

bool MathModel::ensureInequalityCapacity() const
{
    return inequality_count_ < core::SystemSettings::MAX_INEQUALITIES_PER_MODEL;
}

bool MathModel::ensureFunctionCapacity() const
{
    return function_count_ < core::SystemSettings::MAX_FUNCTIONS_PER_MODEL;
}

