            copySmallName(items_[index].name, name);
            items_[index].active = true;
            return true;
        }
    }
    items_[count_].uid = uid;
    copySmallName(items_[count_].name, name);
    items_[count_].active = true;
    count_ += 1U;
    return true;
}

bool CircuitRegistry::remove(std::uint32_t uid)
{
