    Circuit* parent;
    Pin* boundary_pins[core::SystemSettings::MAX_BUS_PINS];
    std::size_t boundary_count;
};

class Circuit {
public:
    explicit Circuit(core::PagedAllocator* allocator);

    bool initialize(std::uint32_t uid, const char* name, Circuit* parent = static_cast<Circuit*>(0));
    std::uint32_t uid() const;
    const char* name() const;
    Circuit* parentCircuit() const;
    core::PagedAllocator* allocator() const;

    Pin* addPin(const char* name, std::uint32_t variable_uid = 0U, std::uint32_t bit_index = 0U);
    Bus* addBus(const char* name);
    bool connect(Pin* pin, Bus* bus);
    bool disconnect(Pin* pin);
    bool lockPin(Pin* pin, bool value);
    bool unlockPin(Pin* pin);
    bool addGate(Pin* pin_a, Pin* pin_b, Pin* pin_c, std::uint8_t truth_byte, Virtual3PinGate** output_gate = static_cast<Virtual3PinGate**>(0));
    bool addSubcircuitInstance(const char* name, Circuit* blueprint, SubcircuitInstance** output_instance = static_cast<SubcircuitInstance**>(0));

    Pin* pinByUid(std::uint32_t uid) const;
    Pin* pinByIndex(std::size_t index) const;
    Pin* firstPinForSolver() const;
    Virtual3PinGate* gateByIndex(std::size_t index) const;
    Virtual3PinGate* firstGateForSolver() const;
    Bus* busByUid(std::uint32_t uid) const;
    SubcircuitInstance* subcircuitByUid(std::uint32_t uid) const;

    std::size_t pinCount() const;
    std::size_t busCount() const;
    std::size_t gateCount() const;
    std::size_t subcircuitCount() const;

private:
    bool copyName(char* destination, std::size_t destination_size, const char* source) const;
    void appendPin(Pin* pin);
    void appendGate(Virtual3PinGate* gate);
    void appendBus(Bus* bus);
    void appendSubcircuit(SubcircuitInstance* instance);

    core::PagedAllocator* allocator_;
    Circuit* parent_;
    std::uint32_t uid_;
    char name_[64];
    Pin* first_pin_;
    Pin* last_pin_;
    Virtual3PinGate* first_gate_;
    Virtual3PinGate* last_gate_;
    Bus* first_bus_;
    Bus* last_bus_;
    SubcircuitInstance* first_instance_;
    SubcircuitInstance* last_instance_;
    std::size_t pin_count_;
    std::size_t bus_count_;
    std::size_t gate_count_;
    std::size_t subcircuit_count_;
    std::uint32_t next_pin_uid_;
    std::uint32_t next_gate_uid_;
    std::uint32_t next_bus_uid_;
    std::uint32_t next_instance_uid_;
};

} // namespace circuit
} // namespace semon

#endif

#ifndef SEMON_CIRCUIT_SOLVER_HPP
#define SEMON_CIRCUIT_SOLVER_HPP

#include <cstddef>
#include <cstdint>

#include "circuit/CircuitTopology.hpp"

namespace semon {
namespace circuit {

typedef bool (*PropagationHook)(std::uint64_t current_cycle,
                                std::size_t active_gates_count,
                                void* userdata);

struct DiagnosticStepInfo {
    std::uint32_t implication_depth;
    std::uint32_t gate_uid;
    std::uint8_t assigned_mask;
    const Pin* active_pin;
    std::uint64_t diagnostic_cycle;
    void* userdata;
};

typedef bool (*DiagnosticHook)(const DiagnosticStepInfo* info, void* userdata);

class Solver {
public:
    Solver() = delete;

    static bool propagate(Circuit& circuit,
                          PropagationHook hook = static_cast<PropagationHook>(0),
                          void* userdata = static_cast<void*>(0),
                          DiagnosticHook diagnostic_hook = static_cast<DiagnosticHook>(0),
                          void* diagnostic_userdata = static_cast<void*>(0));
};

} // namespace circuit
} // namespace semon

#endif

#ifndef SEMON_CIRCUIT_VIRTUAL_GATE_HPP
#define SEMON_CIRCUIT_VIRTUAL_GATE_HPP

#include <cstdint>

#include "circuit/CircuitTopology.hpp"
#include "math/MathTypes.hpp"

namespace semon {
namespace circuit {

class Virtual3PinGate {
public:
    static constexpr std::uint8_t TRUTH_AND = 0x87U;
    static constexpr std::uint8_t TRUTH_XOR = 0x69U;
    static constexpr std::uint8_t TRUTH_OR = 0xEFU;
    static constexpr std::uint8_t TRUTH_EQUAL = 0x96U;
    static constexpr std::uint8_t TRUTH_BUFFER = 0x09U;
    static constexpr std::uint8_t TRUTH_INVERT = 0x06U;
    static constexpr std::uint8_t TRUTH_UNIVERSAL_FREEDOM = 0xFFU;
    static constexpr std::uint8_t TRUTH_UNIVERSAL_CONTRADICTION = 0x00U;

    Virtual3PinGate();

    bool initialize(std::uint32_t uid,
                    Pin* pin_a,
                    Pin* pin_b,
                    Pin* pin_c,
                    std::uint8_t truth_byte,
                    Circuit* parent);

    std::uint32_t uid() const;
    Pin* pinA() const;
    Pin* pinB() const;
    Pin* pinC() const;
    std::uint8_t truthByte() const;
    Circuit* parentCircuit() const;
    bool isReleased() const;
    void markReleased();
    Virtual3PinGate* nextInCircuit() const;
    Virtual3PinGate* previousInCircuit() const;
    void setNextInCircuit(Virtual3PinGate* next);
    void setPreviousInCircuit(Virtual3PinGate* previous);

    static std::uint8_t invertPinA(std::uint8_t truth_byte);
    static std::uint8_t invertPinB(std::uint8_t truth_byte);
    static std::uint8_t invertPinC(std::uint8_t truth_byte);
    static bool combinationAllowed(std::uint8_t truth_byte, bool a, bool b, bool c);
    static std::uint8_t truthByteFor(math::MathOperation operation);

private:
    static constexpr std::uint8_t MASK_A = 0x55U;
    static constexpr std::uint8_t MASK_B = 0x33U;
    static constexpr std::uint8_t MASK_C = 0x0FU;
    static constexpr std::uint8_t MASK_EVEN_A = 0xAAU;
    static constexpr std::uint8_t MASK_EVEN_B = 0xCCU;

    std::uint32_t uid_;
    Pin* pin_a_;
    Pin* pin_b_;
    Pin* pin_c_;
    Virtual3PinGate* next_in_circuit_;
    Virtual3PinGate* previous_in_circuit_;
    std::uint8_t truth_byte_;
    Circuit* parent_;
    bool released_;
};

} // namespace circuit
} // namespace semon

#endif
